mapper.select:
SELECT id, produce_id AS produceId, operation, flow_name AS flowName, plate_no AS plateNo, hole_no AS holeNo, template_plate_no AS templatePlateNo, template_hole_no AS templateHoleNo, layout, hole_number AS holeNumber, origin_concentration AS originConcentration, return_state AS returnState, remark, operator, operate_time AS operateTime, before_flow_name AS beforeFlowName FROM yk_sample_flow_log
AND produce_id = #{query.produceId}
AND operation = #{query.operation}
AND flow_name LIKE CONCAT('%', #{query.flowName}, '%')
AND (plate_no LIKE CONCAT('%', #{query.plateNo}, '%') OR template_plate_no LIKE CONCAT('%', #{query.plateNo}, '%'))
AND template_plate_no = #{query.templatePlateNo}
AND operator LIKE CONCAT('%', #{query.operator}, '%')
AND operate_time >= #{query.startTime}
AND operate_time <= #{query.endTime}
ORDER BY operate_time DESC
